class Palindrome:
    def is_palindrome(self, string: str, l: int, r: int) -> bool:
        if l >= r:
            return True
        if not string[l].isalnum():
            return self.is_palindrome(string, l + 1, r)
        if not string[r].isalnum():
            return self.is_palindrome(string, l, r - 1)
        if string[l].lower() != string[r].lower():
            return False
        return self.is_palindrome(string, l + 1, r - 1)

class PalindromeGenerator:

    def __init__(self):
        self.palindrome_checker = Palindrome()

    def _longest_palindromic_postfix(self, string: str) -> str:
        n = len(string)
        for i in range(n):
            if self.palindrome_checker.is_palindrome(string, i, n - 1):
                return string[i:]
        return ''

    def make_palindrome(self, string: str) -> str:
        postfix = self._longest_palindromic_postfix(string)
        prefix = string[:len(string) - len(postfix)]
        return string + prefix[::-1]

